package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testToStringArray() throws Exception {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Mock input values
        Object[] values = { "value1", 2, null, "value4" };

        // Mock the private method toStringArray
        when(csvFormat.toStringArray(values)).thenCallRealMethod();

        // Invoke the private method using reflection
        String[] result = invokePrivateMethod(csvFormat, "toStringArray", values);

        // Expected output
        String[] expected = { "value1", "2", null, "value4" };

        // Assert the result
        assertArrayEquals(expected, result);
    }

    private String[] invokePrivateMethod(CSVFormat csvFormat, String methodName, Object... args) throws Exception {
        Class<?>[] argTypes = new Class[args.length];
        for (int i = 0; i < args.length; i++) {
            argTypes[i] = args[i].getClass();
        }
        java.lang.reflect.Method method = CSVFormat.class.getDeclaredMethod(methodName, argTypes);
        method.setAccessible(true);
        return (String[]) method.invoke(csvFormat, args);
    }
}
